import React, { useState } from 'react';
import PlayerTable from './PlayerTable';
import TeamDisplay from './TeamDisplay';
import Footer from './Footer';
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';
import { v4 as uuidv4 } from 'uuid';

function App() {
  const [numPlayers, setNumPlayers] = useState(10);
  const [numTeams, setNumTeams] = useState(3);
  const [players, setPlayers] = useState(Array.from({ length: 10 }, () => ({
    id: uuidv4(),
    name: '',
    rating: '3 (Neutral)', // Default rating: 3 (Neutral)
  })));
  const [previousPlayers, setPreviousPlayers] = useState([]);
  const [teams, setTeams] = useState([]);
  const [message, setMessage] = useState('');
  const [showDetails, setShowDetails] = useState(false);
  const [canRandomize, setCanRandomize] = useState(true);
  const [isDescriptionCollapsed, setIsDescriptionCollapsed] = useState(true);  // To show or hide the description
  const [isTableCollapsed, setIsTableCollapsed] = useState(false);
  const [namesText, setNamesText] = useState("");
  const [isTablePopulated, setIsTablePopulated] = useState(false);  // NEW STATE TO TRACK POPULATED TABLE

  // Function to handle collapsing/expanding the description section
  const toggleDescriptionCollapse = () => {
    setIsDescriptionCollapsed(!isDescriptionCollapsed);
  };

  const handleNumPlayersChange = (newNumPlayers) => {
    if (newNumPlayers > players.length) {
      const additionalPlayers = Array.from({ length: newNumPlayers - players.length }, () => ({
        id: uuidv4(),
        name: '',
        rating: 5,
      }));
      setPlayers((prevPlayers) => [...prevPlayers, ...additionalPlayers]);
    } else {
      setPlayers((prevPlayers) => prevPlayers.slice(0, newNumPlayers));
    }
    setNumPlayers(newNumPlayers);
  };

  const incrementPlayers = () => handleNumPlayersChange(numPlayers + 1);
  const decrementPlayers = () => handleNumPlayersChange(numPlayers > 1 ? numPlayers - 1 : 1);

  const toggleTableCollapse = () => setIsTableCollapsed(!isTableCollapsed);

  const handleNamesTextChange = (e) => {
    setNamesText(e.target.value);
  };

  const populateTableFromNames = () => {
    const nameLines = namesText.split('\n').filter(line => line.trim() !== '');

    const parsedNames = nameLines
      .filter(line => /^\d+\.\s*/.test(line))  // Detect lines starting with a number and a period
      .map(line => {
        const name = line.replace(/^\d+\.\s*/, '').trim();
        return { id: uuidv4(), name, rating: 3 };
      })
      .filter(player => player.name !== '');  // Filter out blank names

    setPlayers(parsedNames);
    setNumPlayers(parsedNames.length);
    setNamesText("");
    setIsTablePopulated(true);  // SET TABLE POPULATED TO TRUE
  };

  const calculateTeamsWithPairing = () => {
    // Step 1: Separate players into strong, weak, and neutral categories
    const strongPlayers = players.filter(player => player.rating >= 4); // Strong: rating >= 4
    const weakPlayers = players.filter(player => player.rating <= 2);  // Weak: rating <= 2
    const neutralPlayers = players.filter(player => player.rating > 2 && player.rating < 4);  // Neutral: rating 3

    // Step 2: Create empty teams
    let teams = Array.from({ length: numTeams }, () => []);

    // Step 3: Assign strong and weak players to teams first (pairing logic)
    let teamIndex = 0;
    [...strongPlayers, ...weakPlayers].forEach((player) => {
      teams[teamIndex % numTeams].push(player);
      teamIndex++;
    });

    // Step 4: Distribute neutral players evenly across teams
    const shuffledNeutralPlayers = shuffleArray(neutralPlayers);
    shuffledNeutralPlayers.forEach((player) => {
      teams[teamIndex % numTeams].push(player);
      teamIndex++;
    });

    // Step 5: Ensure all players are distributed
    const allPlayersAssigned = teams.flat().length === players.length;

    if (!allPlayersAssigned) {
      const remainingPlayers = players.filter(p => !teams.flat().includes(p));
      remainingPlayers.forEach((player) => {
        teams[teamIndex % numTeams].push(player);
        teamIndex++;
      });
    }

    // Step 6: Update the teams state and message
    setTeams(teams);
    console.log("Teams balanced:", teams); // <-- Check this in your browser's console
    setMessage('Teams balanced with strong, weak, and neutral players.');
  };

  const resetOptimization = () => {
    setTeams([]);
    setMessage('');
  };

  const randomizeTeams = () => {
    if (canRandomize) {
      setPreviousPlayers(players); // Store the current state before shuffling
      const shuffledPlayers = shuffleArray(players); // Shuffle players, but keep their ratings intact
      setPlayers(shuffledPlayers); // Update the players with the shuffled order
      resetOptimization(); // Reset the teams for recalculation
      setCanRandomize(false); // Disable further randomization until another action is taken
    }
  };  

  const undoRandomTeams = () => {
    if (previousPlayers.length > 0) {
      setPlayers(previousPlayers);
      resetOptimization();
      setCanRandomize(true);
    }
  };

  const handlePlayerChange = (newPlayers) => {
    setPlayers(newPlayers);
    resetOptimization();
    setCanRandomize(true);
  };

  const calculateAverageRating = (team) => {
    if (!team || team.length === 0) return 0;
    const totalRating = team.reduce((acc, player) => {
      const rating = parseFloat(player.rating);
      return acc + (isNaN(rating) ? 0 : rating);
    }, 0);

    const average = totalRating / team.length;
    return isNaN(average) ? 0 : average;
  };

  const shuffleArray = (array) => {
    const clonedArray = [...array];
    for (let i = clonedArray.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [clonedArray[i], clonedArray[j]] = [clonedArray[j], clonedArray[i]];
    }
    return clonedArray;
  };

  const copyNamesToClipboard = () => {
    const formattedNames = teams.map((team, index) => {
      const teamHeader = `Team ${index + 1}`;
      const teamNames = team.map(player => player.name).join('\n');
      return `${teamHeader}\n${teamNames}`;
    }).join('\n\n');

    navigator.clipboard.writeText(formattedNames)
      .then(() => alert("Team names copied to clipboard!"))
      .catch(err => console.error("Error copying to clipboard:", err));
  };

  const handleDragEnd = (result) => {
    const { source, destination } = result;

    // If there's no destination (dropped outside any droppable), return
    if (!destination) return;

    // If the player was dropped in the same spot, return
    if (
      source.droppableId === destination.droppableId &&
      source.index === destination.index
    ) {
      return;
    }

    // Get the source and destination team indices
    const sourceTeamIndex = parseInt(source.droppableId.split('-')[1], 10);
    const destinationTeamIndex = parseInt(destination.droppableId.split('-')[1], 10);

    // Get the player being dragged
    const draggedPlayer = teams[sourceTeamIndex][source.index];

    // Remove the player from the source team
    const updatedSourceTeam = [...teams[sourceTeamIndex]];
    updatedSourceTeam.splice(source.index, 1);

    // Add the player to the destination team
    const updatedDestinationTeam = [...teams[destinationTeamIndex]];
    updatedDestinationTeam.splice(destination.index, 0, draggedPlayer);

    // Update the teams state
    const updatedTeams = [...teams];
    updatedTeams[sourceTeamIndex] = updatedSourceTeam;
    updatedTeams[destinationTeamIndex] = updatedDestinationTeam;

    setTeams(updatedTeams);
  };  

  return (
    <div className="App container">
      <h1>Make My Futsal Team</h1>

      <p className="info text-primary font-weight-bold">
        ℹ️ Keep all player ratings the same to create random teams balanced only by ratings.
      </p>

      {/* Description Collapse Section */}
      <div className="mb-3">
        <button className="btn btn-info" onClick={toggleDescriptionCollapse}>
          {isDescriptionCollapsed ? "Show" : "Hide"} How This App Works
        </button>
        <div className={`collapse ${!isDescriptionCollapsed ? 'show' : ''}`}>
          <div className="mt-3">
            <p>This app helps you balance futsal teams based on player ratings.</p>
            <p>Players are rated on a scale from <strong>1 to 5</strong>:</p>
            <ul>
              <li><strong>1</strong> - Weak (lowest skill level)</li>
              <li><strong>3</strong> - Neutral (default rating)</li>
              <li><strong>5</strong> - Strong (highest skill level)</li>
            </ul>
            <p>To maintain fair teams, strong and weak players are evenly distributed across teams.</p>
            <p>Players with a neutral rating are randomly assigned to teams. You can adjust player ratings and recalculate teams for better balance.</p>
          </div>
        </div>
      </div>

      <div className="mb-3">
        <label htmlFor="namesText">Paste list from Telegram:</label>
        <textarea
          id="namesText"
          value={namesText}
          onChange={handleNamesTextChange}
          placeholder={`7 Nov, THURSDAY, SAFRA TAMPINES, 9PM - 11PM. Pitch 4\n1.Name \n2.Name...`}
          className="form-control"
          rows="4"
        />
        <button className="btn btn-primary mt-2" onClick={populateTableFromNames}>
          Populate Table
        </button>
      </div>

      <div className="mb-3">
        <button className="btn btn-secondary" onClick={toggleTableCollapse}>
          {isTableCollapsed ? "Show Player Input Table" : "Hide Player Input Table"}
        </button>
      </div>

      {!isTableCollapsed && (
        <PlayerTable players={players} setPlayers={handlePlayerChange} showDetails={true} />
      )}

      {/* CONDITIONAL RENDERING OF "NUMBER OF PLAYERS" */}
      {isTablePopulated && (
        <div className="mb-3">
          <label>Number of Players:</label>
          <div className="input-group">
            <button className="btn btn-outline-secondary" onClick={decrementPlayers}>-</button>
            <input
              type="number"
              value={numPlayers}
              readOnly
              className="form-control"
            />
            <button className="btn btn-outline-secondary" onClick={incrementPlayers}>+</button>
          </div>

        </div>
      )}

      <div className="mb-3">
        <label htmlFor="numTeams">Number of Teams:</label>
        <input
          type="number"
          id="numTeams"
          value={numTeams}
          onChange={(e) => setNumTeams(parseInt(e.target.value, 10))}
          min="2"
          className="form-control"
        />
      </div>

      <div className="d-flex flex-wrap mt-3">
        {/* Balance Teams Button */}
        <button
          className="btn btn-primary mr-2"
          onClick={calculateTeamsWithPairing}
          title="Balance teams by pairing strong and weak players evenly."
        >
          Assign Teams
        </button>

        {/* Reset Teams Button */}
        <button
          className="btn btn-secondary mr-2"
          onClick={resetOptimization}
          title="Clear all teams and reset the process."
        >
          Reset Teams
        </button>

        {/* Randomize Teams Button
        <button
          className="btn btn-warning mr-2"
          onClick={randomizeTeams}
          disabled={!canRandomize}
          title="Randomly assign players to teams without considering ratings."
        >
          Shuffle Players
        </button> */}

        {/* Undo Shuffle Button */}
        <button
          className="btn btn-danger"
          onClick={undoRandomTeams}
          title="Undo the last randomization and restore the previous teams."
        >
          Undo Shuffle
        </button>
      </div>

			{message && (
				<p className="text-danger font-weight-bold mt-3">
					{message}
				</p>
			)}

      <div className="form-check mt-3">
        <input
          className="form-check-input"
          type="checkbox"
          checked={showDetails}
          onChange={() => setShowDetails(!showDetails)}
        />
        <label className="form-check-label">
          Show Rating, Team Columns in Output
        </label>
      </div>

      {teams.length > 0 && (
        <>
          <button className="btn btn-info mt-3" onClick={copyNamesToClipboard}>
            Copy Names to Clipboard
          </button>
          <TeamDisplay teams={teams} showDetails={showDetails} calculateAverageRating={calculateAverageRating} />
        </>
      )}

      <Footer />
    </div>
  );
}

export default App;
